def get_tag_label(concept_id: int | str) -> str:
    """Return the English label for a concept ID, with fallback."""
    try:
        cid = int(concept_id)
    except (TypeError, ValueError):
        return f"Concept {concept_id}"
    return CONCEPT_TAG_MAP.get(cid, f"Concept {cid}")
